def find_character(string, char):
    from collections import deque

    queue = deque(enumerate(string))  # Use a queue for BFS with indices
    while queue:
        index, current = queue.popleft()  # Get both index and character
        if current == char:
            return index  # Return the index of the first occurrence

    return -1  # Return -1 if the character is not found

def sort_string_reverse(string):
